import styles from "../../styles/Room.module.css";
import React, { useState } from "react";
import { joinRoom } from "../../services/api";
import { useNavigate } from "react-router-dom";

export default function JoinRoom() {
    const [roomCode, setRoomCode] = useState('');
    const [name, setName] = useState('');
    const navigate = useNavigate();

    const joinRoomWithCode = async () => {
        if (!roomCode || !name) {
            alert("Please provide both a room code and a name.");
            return;
        }

        try {
            const players = await joinRoom(roomCode, name);
            const playerId = players.data.find(player => player.name === name)?.id;
            const index = players.data.find(player => player.name === name)?.index;
            // Join the room
            navigate(`/joined`, {
                state: {
                    current: players.data,
                    roomCode: roomCode,
                    playerId: playerId,
                    index: index
                }
            });
        } catch (error) {
            console.error("Failed to join room:", error);
            alert("Failed to join room. Please check the room code and try again.");
        }
    };

    return (
        <>
            <textarea
                value={name}
                onChange={(e) => {setName(e.target.value.toUpperCase())}}
                rows={2}
                cols={5}
                placeholder="Player Name"
                className={styles.playerNameBox}
            />
            <textarea
                value={roomCode}
                onChange={(e) => {setRoomCode(e.target.value.toUpperCase())}}
                rows={2}
                cols={5}
                placeholder="Room Code"
                className={styles.roomCodeBox}
            />
            <button className={styles.textWrapper2} onClick={joinRoomWithCode}>JOIN ROOM</button>
        </>
    );
}
