import styles from "../../styles/Room.module.css";
import React, {useState} from "react";
import {useNavigate} from "react-router-dom";
import {createRoom, joinRoom} from "../../services/api";

export default function RoomComponents() {
    const [name, setName] = useState('');
    const navigate = useNavigate();

    const handleJoin = async () => {
        // const res = await joinRoom();
        // const roomId = res.data.code;
        navigate(`/joinRoom`, {});
    };

    const createRoomProcess = async () => {
        const room = await createRoom();
        const players = await joinRoom(room.data.code, name);
        const playerId = players.data.find(player => player.name === name)?.id;
        const index = players.data.find(player => player.name === name)?.index;
        navigate(`/joined`, {
            state: {
                current: players.data,
                roomCode: room.data.code,
                playerId: playerId,
                index: index
            }
        });
    };

    return (
        <>
            <textarea
                value={name}
                onChange={(e) => {setName(e.target.value.toUpperCase())}}
                rows={2}
                cols={5}
                placeholder="Player Name"
                className={styles.roomCodeBox}
            />
            <button className={styles.textWrapper} onClick={handleJoin}>JOIN ROOM</button>
            <button className={styles.textWrapper2} onClick={createRoomProcess}>CREATE ROOM</button>
        </>
    );
}
